/**
 * Simple directory scanner for .c files
 * This is a simplified implementation - in production would use proper directory traversal
 */
static void scan_directory_recursive(String dir_path, SourceScanResult *result)
{
	// For now, we'll use a simple approach: check common source directories
	// A full implementation would use FindFirstFile/FindNextFile on Windows
	// or opendir/readdir on POSIX

	// Check src/ directory
	static const char *common_paths[] = { "src/main.c",
										  "src/cli.c",
										  "src/commands/cmd_version.c",
										  "src/commands/cmd_help.c",
										  "src/commands/cmd_init.c",
										  "src/commands/cmd_build.c",
										  "src/commands/cmd_clean.c",
										  NULL };

	for (int i = 0; common_paths[i] != NULL; i++) {
		if (result->count < MAX_SOURCE_FILES) {
			boolResult check = fun_file_exists((String)common_paths[i]);
			if (fun_error_is_ok(check.error) && check.value) {
				result->sources[result->count] = (String)common_paths[i];
				result->count++;
			}
		}
	}

	// Also check fun directory
	static const char *fun_paths[] = { "src/fun/platform.c",
									   "src/build/detector.c",
									   "src/build/generator.c",
									   "src/build/executor.c", NULL };

	for (int i = 0; fun_paths[i] != NULL; i++) {
		if (result->count < MAX_SOURCE_FILES) {
			boolResult check = fun_file_exists((String)fun_paths[i]);
			if (fun_error_is_ok(check.error) && check.value) {
				result->sources[result->count] = (String)fun_paths[i];
				result->count++;
			}
		}
	}
}

/**
 * Recursively scan src/ for .c source files
 */
SourceScanResult build_scan_sources(void)
{
	SourceScanResult result;
	result.count = 0;
	result.error_message = (String) "";

	scan_directory_recursive((String) "src", &result);

	return result;
}

/**
 * Build sources string for compiler command
 */
static void build_sources_string(SourceScanResult scan_result, char *buffer,
								 size_t buffer_size)
{
	buffer[0] = '\0';
	size_t pos = 0;

	for (size_t i = 0; i < scan_result.count; i++) {
		StringLength src_len = fun_string_length(scan_result.sources[i]);
		if (pos + src_len + 2 < buffer_size) {
			fun_string_copy(scan_result.sources[i], buffer + pos);
			pos += src_len;
			buffer[pos++] = ' ';
			buffer[pos] = '\0';
		}
	}
}

/**
 * Generate Windows build script
 */
BuildGenerationResult build_generate_windows(SourceScanResult scan_result)
{
	BuildGenerationResult result;
	static char script_buffer[4096];
	static char sources_buffer[MAX_SOURCES_LENGTH];

	result.script_path = (String) "build-windows-amd64.bat";

	// Build sources string
	build_sources_string(scan_result, sources_buffer, sizeof(sources_buffer));

	// Generate script content
	StringLength platform_len = 14; // "windows-amd64"
	int written = 0;

	// Manual string formatting since we don't have sprintf
	char *ptr = script_buffer;

	// Copy template header
	const char *header =
		"@ECHO OFF\r\nREM Build script generated by fun build tool\r\nREM Platform: windows-amd64\r\n\r\n";
	StringLength header_len = fun_string_length((String)header);
	fun_string_copy((String)header, ptr);
	ptr += header_len;

	// Add GCC command
	const char *gcc_cmd =
		"REM Compile with GCC\r\ngcc --std=c17 -Os -nostdlib -fno-builtin -fno-exceptions -fno-unwind-tables -e main -mconsole -I . -I vendor/fundamental/include vendor/fundamental/src/startup/startup.c vendor/fundamental/arch/startup/windows-amd64/windows.c ";
	StringLength gcc_len = fun_string_length((String)gcc_cmd);
	fun_string_copy((String)gcc_cmd, ptr);
	ptr += gcc_len;

	// Add sources
	StringLength sources_len = fun_string_length((String)sources_buffer);
	fun_string_copy((String)sources_buffer, ptr);
	ptr += sources_len;

	// Add rest of command
	const char *rest =
		" vendor/fundamental/src/console/console.c vendor/fundamental/src/string/stringConversion.c vendor/fundamental/src/string/stringOperations.c vendor/fundamental/src/string/stringTemplate.c vendor/fundamental/src/string/stringValidation.c vendor/fundamental/arch/console/windows-amd64/console.c vendor/fundamental/arch/memory/windows-amd64/memory.c -lkernel32 -o app.exe\r\n\r\nstrip --strip-unneeded app.exe\r\n\r\nECHO Build complete: app.exe\r\n";
	StringLength rest_len = fun_string_length((String)rest);
	fun_string_copy((String)rest, ptr);
	ptr += rest_len;
	*ptr = '\0';

	// Write to file
	StringLength total_len = fun_string_length((String)script_buffer);
	MemoryResult mem_result = fun_memory_allocate(total_len);
	if (fun_error_is_error(mem_result.error)) {
		result.status = BUILD_GENERATED_ERROR;
		result.error_message = (String) "Failed to allocate memory";
		return result;
	}
	fun_string_copy((String)script_buffer, (char *)mem_result.value);

	AsyncResult write_result =
		fun_write_memory_to_file((Write){ .file_path = result.script_path,
										  .input = mem_result.value,
										  .bytes_to_write = total_len });
	fun_async_await(&write_result);

	voidResult free_result = fun_memory_free(&mem_result.value);
	(void)free_result;

	if (write_result.status == ASYNC_COMPLETED) {
		result.status = BUILD_GENERATED_SUCCESS;
		result.error_message = (String) "";
	} else {
		result.status = BUILD_GENERATED_ERROR;
		result.error_message = (String) "Failed to write file";
	}

	return result;
}

